#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1005;
const ll inf=-1e16;
ll n,m,a[N][N],dp[N][N][2];
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++) cin>>a[i][j];
	}
	for(int i=2;i<=n;i++)
	{
		dp[i][1][0]=dp[i][1][1]=inf;
	}
	for(int i=1;i<=m;i++)
	{
		if(i==1)
		{
			dp[1][1][0]=dp[1][1][1]=a[1][1];
			goto nxt;
		}
		for(int j=1;j<=n;j++)
		{
			dp[j][i][0]=dp[j][i][1]=max(dp[j][i-1][0],dp[j][i-1][1])+a[j][i];
		}
		for(int j=n-1;j>=1;j--)
		{
			dp[j][i][1]=max(dp[j][i][1],dp[j+1][i][1]+a[j][i]);
		}
		nxt: ;
		for(int j=2;j<=n;j++)
		{
			dp[j][i][0]=max(dp[j][i][0],dp[j-1][i][0]+a[j][i]);
		}
	}
//	cout<<"___________________________\n";
//	for(int i=1;i<=n;i++)
//	{
//		for(int j=1;j<=m;j++) cout<<dp[i][j][0]<<" "<<dp[i][j][1]<<"  ";
//		cout<<'\n';
//	}
	cout<<dp[n][m][0];
	return 0;
}
